    29→/**
    30→ * Creates a standard CRUD router for any table.
    31→ * @param {string} tableName - The PostgreSQL table name
    32→ * @param {string} [orderCol='created_at'] - Column to order by
    33→ */
    34→function makeRouter(tableName, orderCol = 'created_at') {
    35→  const router  = express.Router();
    36→  const allowed = ALLOWED_COLUMNS[tableName] || [];
    37→
    38→  function filterKeys(data) {
    39→    return Object.keys(data).filter(k => allowed.includes(k) && data[k] !== undefined);
    40→  }
    41→
    42→  // GET / — list all
    43→  router.get('/', async (req, res) => {
    44→    try {
    45→      const { rows } = await pool.query(`SELECT * FROM ${tableName} ORDER BY ${orderCol} DESC`);
    46→      res.json(rows);
    47→    } catch (err) {
    48→      console.error(`[GET ${tableName}]`, err.message);
    49→      res.status(500).json({ message: err.message });
    50→    }
    51→  });
    52→
    53→  // GET /:id — get one
    54→  router.get('/:id', async (req, res) => {
    55→    try {
    56→      const { rows } = await pool.query(`SELECT * FROM ${tableName} WHERE id = $1`, [req.params.id]);
    57→      if (!rows[0]) return res.status(404).json({ message: 'Not found' });
    58→      res.json(rows[0]);
    59→    } catch (err) {
    60→      res.status(500).json({ message: err.message });
    61→    }
    62→  });
    63→
    64→  // POST / — create
    65→  router.post('/', async (req, res) => {
    66→    const keys = filterKeys(req.body);
    67→    if (!keys.length) return res.status(400).json({ message: 'No valid fields provided' });
    68→
    69→    const cols         = keys.join(', ');
    70→    const placeholders = keys.map((_, i) => `$${i + 1}`).join(', ');
    71→    const values       = keys.map(k => req.body[k]);
    72→
    73→    try {
    74→      const { rows } = await pool.query(
    75→        `INSERT INTO ${tableName} (${cols}) VALUES (${placeholders}) RETURNING *`,
    76→        values
    77→      );
    78→      res.status(201).json(rows[0]);
    79→    } catch (err) {
    80→      console.error(`[POST ${tableName}]`, err.message);
    81→      res.status(500).json({ message: err.message });
    82→    }
    83→  });
    84→
    85→  // PUT /:id — update
    86→  router.put('/:id', async (req, res) => {
    87→    const keys = filterKeys(req.body);
    88→    if (!keys.length) return res.status(400).json({ message: 'No valid fields provided' });
    89→
    90→    const setClause = keys.map((k, i) => `${k} = $${i + 1}`).join(', ');
    91→    const values    = [...keys.map(k => req.body[k]), req.params.id];
    92→
    93→    try {
    94→      const { rows } = await pool.query(
    95→        `UPDATE ${tableName} SET ${setClause} WHERE id = $${keys.length + 1} RETURNING *`,
    96→        values
    97→      );
    98→      if (!rows[0]) return res.status(404).json({ message: 'Not found' });
    99→      res.json(rows[0]);
   100→    } catch (err) {
   101→      console.error(`[PUT ${tableName}]`, err.message);
   102→      res.status(500).json({ message: err.message });
   103→    }
   104→  });
   105→
   106→  // DELETE /:id
   107→  router.delete('/:id', async (req, res) => {
   108→    try {
   109→      const { rowCount } = await pool.query(`DELETE FROM ${tableName} WHERE id = $1`, [req.params.id]);
   110→      if (!rowCount) return res.status(404).json({ message: 'Not found' });
   111→      res.json({ message: 'Deleted successfully' });
   112→    } catch (err) {
   113→      res.status(500).json({ message: err.message });
   114→    }
   115→  });
   116→
   117→  return router;
   118→}
   119→
   120→module.exports = makeRouter;
   121→

