     1→const express = require('express');
     2→const bcrypt  = require('bcrypt');
     3→const jwt     = require('jsonwebtoken');
     4→const pool    = require('../db');
     5→const authMiddleware = require('../middleware/auth');
     6→
     7→const router = express.Router();
     8→const SECRET = process.env.JWT_SECRET || 'cortexbuild_secret';
     9→
    10→const VALID_ROLES = ['super_admin','company_owner','admin','project_manager','field_worker','client'];
    11→
    12→// POST /api/auth/register — public self-registration (creates company_owner account)
    13→router.post('/register', async (req, res) => {
    14→  const { name, email, password, company, phone } = req.body;
    15→
    16→  if (!name || !email || !password || !company) {
    17→    return res.status(400).json({ message: 'Name, email, password and company are required' });
    18→  }
    19→  if (password.length < 8) {
    20→    return res.status(400).json({ message: 'Password must be at least 8 characters' });
    21→  }
    22→  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    23→  if (!emailRe.test(email)) {
    24→    return res.status(400).json({ message: 'Invalid email address' });
    25→  }
    26→
    27→  try {
    28→    // Check for duplicate email
    29→    const existing = await pool.query('SELECT id FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    30→    if (existing.rows.length) {
    31→      return res.status(409).json({ message: 'An account with that email already exists' });
    32→    }
    33→
    34→    const hash = await bcrypt.hash(password, 10);
    35→    const { rows } = await pool.query(
    36→      `INSERT INTO users (name, email, password_hash, role, company, phone)
    37→       VALUES ($1, $2, $3, 'company_owner', $4, $5)
    38→       RETURNING id, name, email, role, company, phone, created_at`,
    39→      [name.trim(), email.toLowerCase().trim(), hash, company.trim(), phone || null]
    40→    );
    41→    const newUser = rows[0];
    42→
    43→    const token = jwt.sign(
    44→      { id: newUser.id, email: newUser.email, role: newUser.role, name: newUser.name, company: newUser.company },
    45→      SECRET,
    46→      { expiresIn: '7d' }
    47→    );
    48→
    49→    res.status(201).json({ token, user: newUser });
    50→  } catch (err) {
    51→    console.error('[auth/register]', err);
    52→    res.status(500).json({ message: 'Server error during registration' });
    53→  }
    54→});
    55→
    56→// POST /api/auth/login
    57→router.post('/login', async (req, res) => {
    58→  const { email, password } = req.body;
    59→  if (!email || !password) return res.status(400).json({ message: 'Email and password required' });
    60→
    61→  try {
    62→    const { rows } = await pool.query('SELECT * FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    63→    const user = rows[0];
    64→    if (!user) return res.status(401).json({ message: 'Invalid email or password' });
    65→
    66→    const valid = await bcrypt.compare(password, user.password_hash);
    67→    if (!valid) return res.status(401).json({ message: 'Invalid email or password' });
    68→
    69→    const token = jwt.sign(
    70→      { id: user.id, email: user.email, role: user.role, name: user.name, company: user.company },
    71→      SECRET,
    72→      { expiresIn: '7d' }
    73→    );
    74→
    75→    const { password_hash, ...safeUser } = user;
    76→    res.json({ token, user: safeUser });
    77→  } catch (err) {
    78→    console.error('[auth/login]', err);
    79→    res.status(500).json({ message: 'Server error' });
    80→  }
    81→});
