    93→    res.status(500).json({ message: 'Server error' });
    94→  }
    95→});
    96→
    97→// PUT /api/auth/profile
    98→router.put('/profile', authMiddleware, async (req, res) => {
    99→  const { name, phone } = req.body;
   100→  try {
   101→    const { rows } = await pool.query(
   102→      'UPDATE users SET name=$1, phone=$2 WHERE id=$3 RETURNING id,name,email,role,company,phone,avatar',
   103→      [name, phone, req.user.id]
   104→    );
   105→    res.json(rows[0]);
   106→  } catch (err) {
   107→    res.status(500).json({ message: 'Server error' });
   108→  }
   109→});
   110→
   111→// PUT /api/auth/password
   112→router.put('/password', authMiddleware, async (req, res) => {
   113→  const { currentPassword, newPassword } = req.body;
   114→  if (!currentPassword || !newPassword) return res.status(400).json({ message: 'Both passwords required' });
   115→  if (newPassword.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
   116→
   117→  try {
   118→    const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [req.user.id]);
   119→    const user = rows[0];
   120→    const valid = await bcrypt.compare(currentPassword, user.password_hash);
   121→    if (!valid) return res.status(400).json({ message: 'Current password is incorrect' });
   122→
   123→    const hash = await bcrypt.hash(newPassword, 10);
   124→    await pool.query('UPDATE users SET password_hash=$1 WHERE id=$2', [hash, req.user.id]);
   125→    res.json({ message: 'Password updated successfully' });
   126→  } catch (err) {
   127→    res.status(500).json({ message: 'Server error' });
   128→  }
   129→});
