   131→// GET /api/auth/users — list all users (admin+ only)
   132→router.get('/users', authMiddleware, async (req, res) => {
   133→  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
   134→    return res.status(403).json({ message: 'Insufficient permissions' });
   135→  }
   136→  try {
   137→    const { rows } = await pool.query(
   138→      'SELECT id,name,email,role,company,phone,avatar,created_at FROM users ORDER BY created_at DESC'
   139→    );
   140→    res.json(rows);
   141→  } catch (err) {
   142→    res.status(500).json({ message: 'Server error' });
   143→  }
   144→});
   145→
   146→// POST /api/auth/users — create user (admin+ only)
   147→router.post('/users', authMiddleware, async (req, res) => {
   148→  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
   149→    return res.status(403).json({ message: 'Insufficient permissions' });
   150→  }
   151→
   152→  const { name, email, password, role = 'project_manager', company, phone } = req.body;
   153→  if (!name || !email || !password) return res.status(400).json({ message: 'Name, email, and password are required' });
   154→  if (password.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
   155→  if (!VALID_ROLES.includes(role)) return res.status(400).json({ message: `Invalid role. Must be one of: ${VALID_ROLES.join(', ')}` });
   156→
   157→  try {
   158→    const hash = await bcrypt.hash(password, 10);
   159→    const { rows } = await pool.query(
   160→      'INSERT INTO users (name,email,password_hash,role,company,phone) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id,name,email,role,company,phone,created_at',
   161→      [name, email.toLowerCase().trim(), hash, role, company || 'CortexBuild Ltd', phone || null]
   162→    );
   163→    res.status(201).json(rows[0]);
   164→  } catch (err) {
   165→    if (err.code === '23505') return res.status(409).json({ message: 'Email already in use' });
   166→    console.error('[auth/users POST]', err);
   167→    res.status(500).json({ message: 'Server error' });
   168→  }
   169→});
   170→
   171→// DELETE /api/auth/users/:id — delete user (super_admin / company_owner only)
   172→router.delete('/users/:id', authMiddleware, async (req, res) => {
   173→  if (!['super_admin','company_owner'].includes(req.user.role)) {
   174→    return res.status(403).json({ message: 'Insufficient permissions' });
   175→  }
   176→  if (req.params.id === req.user.id) return res.status(400).json({ message: 'Cannot delete your own account' });
   177→
   178→  try {
   179→    const { rowCount } = await pool.query('DELETE FROM users WHERE id = $1', [req.params.id]);
   180→    if (!rowCount) return res.status(404).json({ message: 'User not found' });
   181→    res.json({ message: 'User deleted' });
   182→  } catch (err) {
   183→    res.status(500).json({ message: 'Server error' });
   184→  }
   185→});
   186→
   187→module.exports = router;
