    23→export function AIAssistant() {
    24→  const [messages, setMessages] = useState<Message[]>([]);
    25→  const [input, setInput] = useState('');
    26→  const [selectedAgent, setSelectedAgent] = useState<string>('safety');
    27→  const [isTyping, setIsTyping] = useState(false);
    28→  const [suggestions, setSuggestions] = useState<string[]>([
    29→    "Show me all projects",
    30→    "What invoices are overdue?",
    31→    "Show me open safety incidents",
    32→    "What's our current budget position?",
    33→    "Show me open RFIs",
    34→    "What's in our tender pipeline?",
    35→  ]);
    36→
    37→  const agents: Agent[] = [
    38→    { id: 'safety', name: 'Safety Analyser', icon: AlertCircle, active: true, lastUsed: '2 hours ago' },
    39→    { id: 'rfi', name: 'RFI Responder', icon: FileText, active: true, lastUsed: '1 day ago' },
    40→    { id: 'rams', name: 'RAMS Generator', icon: Zap, active: true, lastUsed: '3 days ago' },
    41→    { id: 'report', name: 'Daily Report Agent', icon: BarChart3, active: true, lastUsed: '1 hour ago' },
    42→    { id: 'change', name: 'Change Order Agent', icon: DollarSign, active: true, lastUsed: '5 days ago' },
    43→    { id: 'tender', name: 'Tender Scorer', icon: Check, active: true, lastUsed: '1 week ago' }
    44→  ];
    45→
    46→
    47→  const handleSendMessage = async (text?: string) => {
    48→    const messageText = text || input;
    49→    if (!messageText.trim() || isTyping) return;
    50→
    51→    const userMessage: Message = {
    52→      id: Date.now().toString(),
    53→      role: 'user',
    54→      content: messageText,
    55→      timestamp: new Date(),
    56→    };
    57→
    58→    setMessages(prev => [...prev, userMessage]);
    59→    setInput('');
    60→    setIsTyping(true);
    61→
    62→    try {
    63→      const result = await aiApi.chat(messageText);
    64→      setMessages(prev => [...prev, {
    65→        id: (Date.now() + 1).toString(),
    66→        role: 'assistant',
    67→        content: result.reply,
    68→        timestamp: new Date(),
    69→      }]);
    70→      if (result.suggestions?.length) setSuggestions(result.suggestions);
    71→    } catch (err) {
    72→      toast.error('AI assistant error. Please try again.');
    73→      setMessages(prev => [...prev, {
    74→        id: (Date.now() + 1).toString(),
    75→        role: 'assistant',
    76→        content: 'Sorry, I encountered an error reaching the backend. Please try again.',
    77→        timestamp: new Date(),
    78→      }]);
    79→    } finally {
    80→      setIsTyping(false);
    81→    }
    82→  };
    83→
    84→  return (
    85→    <div className="h-full flex bg-gradient-to-br from-gray-950 via-gray-900 to-gray-950">
    86→      {/* Left Sidebar - Agents */}
    87→      <div className="w-64 border-r border-gray-800 bg-gray-900/50 p-4 overflow-y-auto">
    88→        <h2 className="mb-4 text-xs font-bold uppercase tracking-widest text-gray-500">AI Agents</h2>
    89→        <div className="space-y-2">
    90→          {agents.map(agent => {
    91→            const Icon = agent.icon;
    92→            return (
    93→              <button
    94→                key={agent.id}
    95→                onClick={() => setSelectedAgent(agent.id)}
    96→                className={clsx(
    97→                  'w-full rounded-xl border p-3 text-left transition-all',
    98→                  selectedAgent === agent.id
    99→                    ? 'border-blue-600 bg-blue-900/30'
   100→                    : 'border-gray-800 bg-gray-800/30 hover:bg-gray-800/50'

