    22→// Insight severity levels
    23→const SEVERITY = {
    24→  critical: { label: 'Critical', color: 'var(--red-400)', bg: 'rgba(248,113,113,0.1)', border: 'rgba(248,113,113,0.3)' },
    25→  high:     { label: 'High',     color: 'var(--orange-400)', bg: 'rgba(251,146,60,0.1)', border: 'rgba(251,146,60,0.3)' },
    26→  medium:   { label: 'Medium',   color: 'var(--amber-400)', bg: 'rgba(245,158,11,0.1)', border: 'rgba(245,158,11,0.3)' },
    27→  low:      { label: 'Low',      color: 'var(--emerald-400)', bg: 'rgba(16,185,129,0.1)', border: 'rgba(16,185,129,0.3)' },
    28→  info:     { label: 'Info',     color: 'var(--blue-400)', bg: 'rgba(59,130,246,0.1)', border: 'rgba(59,130,246,0.3)' },
    29→};
    30→type SeverityKey = keyof typeof SEVERITY;
    31→
    32→// Generate AI insights from data
    33→function generateInsights(
    34→  projects: AnyRow[],
    35→  safety: AnyRow[],
    36→  invoices: AnyRow[],
    37→  rfis: AnyRow[],
